sql:
SELECT COUNT(part_id) AS part_count
FROM parts
WHERE category = 'Mudguards';

SELECT part_name
FROM parts
ORDER BY part_name;

SELECT part_name, msrp
FROM parts
ORDER BY msrp DESC;

external_knowledge:
- 'names' refer to the 'part_id'; 
- 'total sales figures' represent the combined sales of new and existing parts;
- 'first warehouse' corresponds to 'warehouse_id = 1'.

sql:
SELECT SUM(new_sales + existing_sales) AS total_parts_sold
FROM sales
WHERE warehouse_id = 0 AND sale_date BETWEEN '2021-01-01' AND '2021-12-31';
